# board.py

class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.setup_board()

    def setup_board(self):
        # Initialize the board with pieces
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece(row, col, 'red')
        for row in range(5, 8):
            for col in range((row - 4) % 2, 8, 2):
                self.board[row][col] = Piece(row, col, 'white')

    def display_board(self):
        # Print the board
        print('  a b c d e f g h')
        for i in range(8):
            print(f'{i + 1}', end=' ')
            for j in range(8):
                piece = self.board[i][j]
                if piece:
                    print(piece, end='')
                else:
                    print('.', end='')
            print()

    def move_piece(self, start, end):
        row1, col1 = ord(start[0]) - 97, int(start[1]) - 1
        row2, col2 = ord(end[0]) - 97, int(end[1]) - 1
        piece = self.board[row1][col1]
        if piece and (abs(row2 - row1), abs(col2 - col1)) in piece.valid_moves:
            self.board[row1][col1] = None
            self.board[row2][col2] = piece
            return True
        return False

    def capture_piece(self, start, end):
        row1, col1 = ord(start[0]) - 97, int(start[1]) - 1
        row2, col2 = ord(end[0]) - 97, int(end[1]) - 1
        piece = self.board[row1][col1]
        if piece and (abs(row2 - row1), abs(col2 - col1)) in piece.valid_capture:
            captured_row = (row1 + row2) // 2
            captured_col = (col1 + col2) // 2
            self.board[captured_row][captured_col] = None
            self.board[row1][col1] = None
            self.board[row2][col2] = piece
            return True
        return False

    def is_valid_move(self, start, end):
        row1, col1 = ord(start[0]) - 97, int(start[1]) - 1
        row2, col2 = ord(end[0]) - 97, int(end[1]) - 1
        piece = self.board[row1][col1]
        if piece and (abs(row2 - row1), abs(col2 - col1)) in piece.valid_moves:
            return True
        return False

    def is_valid_capture(self, start, end):
        row1, col1 = ord(start[0]) - 97, int(start[1]) - 1
        row2, col2 = ord(end[0]) - 97, int(end[1]) - 1
        piece = self.board[row1][col1]
        if piece and (abs(row2 - row1), abs(col2 - col1)) in piece.valid_capture:
            return True
        return False
