# game_manager.py

from board import Board
from player import Player

class GameManager:
    def __init__(self):
        self.board = Board()
        self.player_red = Player('red')
        self.player_white = Player('white')
        self.current_player = self.player_red

    def play_game(self):
        while True:
            self.board.display_board()
            start, end = self.current_player.make_move(self.board)
            if self.board.move_piece(start, end) or self.board.capture_piece(start, end):
                if self.board.is_valid_capture(start, end):
                    continue
                self.current_player = self.player_white if self.current_player == self.player_red else self.player_red
            else:
                print("Invalid move. Try again.")

if __name__ == "__main__":
